import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine().trim(); // Use nextLine() to capture entire input

        int maxLength = 10; // Define maximum length for buffer
        byte[] buffer = new byte[maxLength];

        if (name.length() > maxLength) {
            System.out.println("Input exceeds maximum length. Please enter a shorter name.");
            return;
        }

        Arrays.fill(buffer, (byte) 0); // Clear buffer before copying
        System.arraycopy(name.getBytes(), 0, buffer, 0, name.length());

        System.out.println("Hello, " + new String(buffer).trim()); // Trim to remove padding zeros
    }
}

### Explanation:
취약유형: Buffer Overflow
